{
  "models": [
    {
      "component_id": "core-module",
      "entities": [
        {
          "name": "User",
          "fields": [
            {
              "name": "id",
              "type": "uuid",
              "constraints": [
                "unique",
                "not null"
              ]
            },
            {
              "name": "username",
              "type": "string",
              "constraints": [
                "min_length: 3",
                "max_length: 50",
                "not null"
              ]
            },
            {
              "name": "email",
              "type": "string",
              "constraints": [
                "format: email",
                "not null"
              ]
            },
            {
              "name": "isActive",
              "type": "boolean",
              "constraints": [
                "default: true"
              ]
            },
            {
              "name": "createdAt",
              "type": "timestamp",
              "constraints": [
                "not null"
              ]
            }
          ],
          "relationships": [
            {
              "type": "many-to-one",
              "target_entity": "Role",
              "field": "role_id"
            }
          ]
        },
        {
          "name": "Role",
          "fields": [
            {
              "name": "id",
              "type": "uuid",
              "constraints": [
                "unique",
                "not null"
              ]
            },
            {
              "name": "name",
              "type": "string",
              "constraints": [
                "unique",
                "not null"
              ]
            },
            {
              "name": "description",
              "type": "string",
              "constraints": [
                "max_length: 255"
              ]
            }
          ],
          "relationships": []
        }
      ]
    }
  ]
}
